<?php

declare(strict_types=1);
namespace App\Http\Controllers\StudentAffairs;
use App\Enums\Gender; use App\Http\Controllers\Controller; use App\Http\Requests\StudentAffairs\GuardianRequest; use App\Models\Guardian; use App\Models\User; use App\Services\StudentAffairs\GuardianService; use Illuminate\Http\Request; use Illuminate\View\View;
class GuardianController extends Controller { public function index(Request $request): View { $guardians=Guardian::with('students')->when($request->search,fn($q,$s)=>$q->where('name','like',"%$s%")->orWhere('national_identity_number','like',"%$s%")->orWhere('phone','like',"%$s%"))->latest()->paginate(15)->withQueryString(); return view('student-affairs.guardians.index',compact('guardians')); } public function create(): View { return view('student-affairs.guardians.form',['guardian'=>new Guardian,'genders'=>Gender::cases(),'users'=>User::whereDoesntHave('guardian')->get()]); } public function store(GuardianRequest $request, GuardianService $service) { $g=$service->save($request->validated()); return redirect()->route('guardians.show',$g)->with('status','Data wali berhasil ditambahkan.'); } public function show(Guardian $guardian): View { $guardian->load('students'); return view('student-affairs.guardians.show',compact('guardian')); } public function edit(Guardian $guardian): View { return view('student-affairs.guardians.form',['guardian'=>$guardian,'genders'=>Gender::cases(),'users'=>User::whereDoesntHave('guardian')->orWhereKey($guardian->user_id)->get()]); } public function update(GuardianRequest $request, Guardian $guardian, GuardianService $service) { $service->save($request->validated(),$guardian); return redirect()->route('guardians.show',$guardian)->with('status','Data wali berhasil diperbarui.'); } public function destroy(Guardian $guardian) { $guardian->update(['is_active'=>false]); $guardian->delete(); return redirect()->route('guardians.index')->with('status','Data wali dinonaktifkan.'); } }
